sql:
SELECT COUNT(DISTINCT ec.election_id) AS number_of_elections
FROM election_candidates ec
WHERE ec.candidate_id = 0;

external_knowledge:
- Cumulative percentage refers to the sum of the percentages of popular votes received by the candidates up to the current row, ordered by the percentage in descending order; 
- Popular votes are the votes cast by individual citizens in an election; 
- Percentage of popular votes refers to the proportion of popular votes received by each candidate out of the total votes cast; 
- Win/Loss status indicates whether the candidate won or lost the election.

sql:
SELECT year
FROM elections
WHERE turnout_percentage = (SELECT MAX(turnout_percentage) FROM elections);
